import {
    controls,
    defaultValuesForm,
    icons
} from "../env.js";
import DOM from "./dom.js";
import Dragable from "./drag.js";
import Hooks from "./FormHooks.js";
import FormManager from "./FormManager.js";
import Marker from "./marker.js";
import {
    mousePosition
} from "./utils.js";


export default class ControlManager {
    constructor(state, api) {
        this._state = state;
        this._api = api;
        this._dom = new DOM();
        this.init();
        
    }


    init() {

        const elementRoot = this._dom.create({
            id: controls.init,
            className: "pick-control",
            inner: icons.root,
            isDraggable: true
        });
        const widgetWrapper = this._dom.create({ id: "widget-wrapper", className: "f--" });
        const controlsWrapper = this._dom.create({id: "controls-wrapper",});

        const inline = this._dom.create({
            id: "inline",
            className: "pick-control",
            inner: icons.inline
        });

        
        

        

        /* */
        this._dom.append(widgetWrapper, elementRoot);
        
        this._dom.append(document.body, widgetWrapper);

        new Dragable({
            body: "#widget-wrapper",
            trigger: "#widget-wrapper",
            storageKey: 'widget',
            type: 'snap',
            allowDragOn: '.pick-control',
            offset: {
                top: 10,
                bottom: 10,
                left: 10,
                right: 10,
            }
        });

        // widgetWrapper, 'widget', 'snap'

        if(this._state.user) {
            this._dom.append(widgetWrapper, controlsWrapper);
            this._dom.append(controlsWrapper, inline);
            
            this._explorerInit(controlsWrapper);

            this._markerInit();
        } else {
            const handleLogin = () => {
                console.log('widget clicked');
                const formManager = new FormManager(this._state);
                const loginForm = formManager.loginForm();
                loginForm.on("formLogin", async (data) => {
                    console.log(data);
                    const res = await this._api.loginUser(data.email, data.password);
                    
                    console.log(res);
                    if(res) {
                        this._state.setStage('init',`formLogin Hook>success`);
                        const apiRes = await this._api.initialize();
                        console.log(apiRes);
                        if(apiRes.isTasks) {
                            this._markerInit();
                        }
                        this._dom.off(elementRoot, 'click', handleLogin);
                        this._dom.append(widgetWrapper, controlsWrapper);
                        this._dom.append(controlsWrapper, inline);
                        this._explorerInit(controlsWrapper);
                        loginForm.removeForm();
                        return res;
                    } else {
                        return false;
                    }
                });

                loginForm.on("formCancel", () => {
                    console.log('formCancel');
                    loginForm.removeForm();
                });
            };

            this._dom.on(elementRoot, 'click', handleLogin);
        }

        this._dom.on(inline, 'click', () => {

            const user = this._state.user;
            if (!user) {
                console.error('User not found');
                return;
            }

            if (this._state.stage === 'init' || this._state.stage === 'marker_click' ) {
                this._state.setStage('overlay', 'inline');
                this._createOverlay();
            } else {
                console.warn(`Stage is ${this._state.stage}. it's only allowed in init stage`);
            }
        });

        // console.log(this._state.user);
        if(this._state.user && this._state.user.role === 'guest'){
            // inline button remove from body
            this._dom.remove(controlsWrapper, inline);
        }


    }

    _explorerInit(wrapper){

        if(this._state.tasks){

            const explore = this._dom.create({
                id: "explore",
                className: "pick-control",
                inner: icons.explore
            });

            this._dom.append(wrapper, explore);
            explore.addEventListener('click', () => {
                this._state.marker.toggleExplorer();
            });
        }
    }

    
    _markerInit() {
        const tasks = this._state.tasks;
        const user = this._state.user;

        if (!user) {
            console.error('User not found');
            return;
        }

        if (!tasks) {
            console.error('Tasks not found');
            return;
        }
        
        const marker = new Marker(this._state , this._api);
        this._state.setState("marker", marker);
        

        this._state.marker.loadMarkers();
        // this._state.marker.explorer();
        // new Dragable({
        //     body: "#explorer",
        //     trigger: ".f-py--m",
        //     storageKey: 'explorer',
        //     type: 'snap',
        //     initialPosition: {
        //         x: 10,
        //         y: 70
        //     },
        //     offset: {
        //         top: 10,
        //         bottom: 10,
        //         left: 70,
        //         right: 70,
        //     }
        // });


        
        this.activeForm = null;

        this._state.marker.on('click', (taskId, isSecondClick) => {
            if (isSecondClick) {
                if (this.activeForm) {
                    this.activeForm.removeForm('marker_click');
                    this.activeForm = null;
                }
                return;
            }
            
            if (this.activeForm) {
                this.activeForm.removeForm('marker_click');
                this.activeForm = null;
            }
            
            // Create a new form for the clicked marker
            const formManager = new FormManager(this._state);
            const hooks = new Hooks(this._api);
            hooks.formCreate(formManager);
            hooks.formUpdate(formManager,()=>{
                this._state.marker.clearActive();
                this._state.marker.taskId = null;
                this.activeForm = null;
            });
            
            formManager.on(formManager._formEvents.fCn, () => {
                this._state.marker.clearActive();
                this._state.marker.taskId = null;
                this.activeForm = null;
            });
            
            formManager.createForm({
                viewportInfo: null,
                id: "TaskFormUpdate",
                type: "update",
                defaultValues: parseInt(taskId),
                reason: 'marker_click'
            });
            
            this.activeForm = formManager;
        });
    }




    _createForm() {
        const formManager = new FormManager(this._state);
        const formHook = new Hooks(this._api);
        formHook.formCreate(formManager);
        formHook.formSubmit(formManager);
        formManager.createForm({
            viewportInfo: null,
            id: "TaskForm",
            type: "create",
            defaultValues: defaultValuesForm
        });
    }

    _createOverlay() {
        const overlay = this._dom.create({ id: "f-overlay" });
        overlay.addEventListener('click', (e) => {

            const mousePos = mousePosition(e);
            this._state.setState("mousePos", mousePos, 'overlay');
            this._removeOverlay();
            this._createForm();
        });
        this._dom.append(document.body, overlay);
    }

    _removeOverlay() {
        const overlay = this._dom.getOne("#f-overlay");
        this._dom.remove(document.body, overlay);
    }

    

}
