import DOM from "./dom.js";
import Dragable from "./drag.js";

export default class Marker {
    constructor(state , api = null) {
        this._state = state;
        this._api = api;
        this._tasks = this._state.tasks;
        this._user = this._state.user;
        this._taskId = null;
        this._previousTaskId = null;
        this.activeForm = null;
        this._dom = new DOM();
        this.clickCallback = null;

        // this._prepareData = this._state.tasks;


    }
    on(eventType, callback) {
        if (eventType === 'click') {
            this.clickCallback = callback;
            this.attachClickListeners();
        }
    }

    addClickListener(marker) {
        if (this._state.stage === 'overlay' ||
            this._state.stage === 'form_created') {
            console.warn(`Stage is ${this._state.stage}. Marker clicks not allowed`);
            return;
        }

        const taskId = this._dom.getAttr(marker, 'data-mkr-id');

        // Remove old listeners before adding new ones
        marker.removeEventListener('click', this.clickHandler);

        if (this._taskId === taskId) {
            this.clearActive();
            this._taskId = null;
            this._state.setStage('marker_double_click', 'marker-double-click');
            if (this.clickCallback) {
                this.clickCallback(taskId, true);
            }
        } else {
            this._previousTaskId = this._taskId;
            this._taskId = taskId;

            this.clearActive();

            // Use a single selector to activate both marker and task item
            this._dom.addClass(`[data-mkr-id="${taskId}"]`, 'active', true);

            this._state.setStage('marker_click', 'marker-click');
            if (this.clickCallback) {
                this.clickCallback(taskId, false);
            }
        }
    }



    clearActive() {
        const markers = this._dom.get('.mkrClick');
        markers.forEach(marker => {
            this._dom.removeClass(marker, 'active');
        });
    }

    createMarker(index, task) {

        const marker = this._dom.create({
            id: "marker",
            className: "mkr mkrClick f--",
            inner: index,
            attributes: {
                'data-mkr-id': task.id
            }
        });

        

        

        
        this._dom.append(document.body, marker);

        // new Dragable(marker,null,'free',{
        //     x: task.screeninfo.document.x,
        //     y: task.screeninfo.document.y
        // });
        
        return marker;
    }
    loadMarkers() {
        this._tasks.forEach((task, index) => {
            this.createMarker(index + 1, task);
        });
    }



    /* explorer */
    filterData() {
        return this._state.tasks.filter(task => {
            // If both filters are active, check both conditions
            if (this.priority && this.status) {
                return task.priority === this.priority && task.status === this.status;
            }
            // If only priority filter is active
            if (this.priority) {
                return task.priority === this.priority;
            }
            // If only status filter is active
            if (this.status) {
                return task.status === this.status;
            }
            // If no filters are active, return all tasks
            return true;
        });
    }

    toggleExplorer() {
        if (document.body.contains(document.querySelector("#explorer"))) {
            this.removeExplorer();
            this.priority = null;
            this.status = null;
        } else {
            this.explorer();
        }
    }

    removeExplorer() {
        const explorer = this._dom.getOne("#explorer");
        document.body.removeChild(explorer);
    }

    explorer() {
        const html = ` <div class="f-gd f-px--n f-py--m"><div class="f-f--j"><div class="f-w--b">Bug Explorer</div><div class="filter-by"><div class="priority"></div><div class="status"></div></div></div></div><div class="f-px--m f-f taskList"></div>`;

        const explorer = this._dom.create({
            id: "explorer",
            className: "f-shadow f-explorer",
            inner: html
        });
        this._dom.append(document.body, explorer);

        const data = this.filterData();
        data.reverse().forEach(task => {
            this.singleTask(task);
        });

        // Attach click listeners after initial task list creation
        this.attachClickListeners();

        const priority = this._state.priority;
        const status = this._state.status;

        const priorityDropdown = new DropdownSelect({
            element: explorer.querySelector('.priority'),
            data: priority,
            type: "single",
            style: "picker",
            placeholder: "Priority",
            isClearable: true,
        });

        priorityDropdown._element.addEventListener('change', (event) => {
            this.priority = event.detail[0]; // Take first value since it's single select
            this.updateTaskList(explorer);
        });

        const statusDropdown = new DropdownSelect({
            element: explorer.querySelector('.status'),
            data: status,
            type: "single",
            style: "picker",
            placeholder: "Status",
            isClearable: true,
        });

        statusDropdown._element.addEventListener('change', (event) => {
            this.status = event.detail[0]; // Take first value since it's single select
            this.updateTaskList(explorer);
        });

        new Dragable({
            body: "#explorer",
            trigger: ".f-py--m",
            storageKey: 'explorer',
            type: 'snap',
            initialPosition: {
                x: 10,
                y: 70
            },
            offset: {
                top: 10,
                bottom: 10,
                left: 70,
                right: 70,
            }
        });
    }

    singleTask(task) {
        // Format the date
        const date = new Date(task.due_date);
        const formattedDate = date.toLocaleDateString('en-US', {
            month: 'long',
            day: 'numeric',
            hour: 'numeric',
            minute: 'numeric'
        });

        const html = ` <div class="f-w--f f-p--m f-e--task mkrClick"data-mkr-id="${task.id}"><div class="f-f--j"><div class="f-pb--s f-s--m f-w--m">${task.title}</div><div class="f--w">${task.priority}</div></div><div class="f-pb--s f-s--m">${task.description}</div><div class="f-s--s">${formattedDate} </div></div>`;
        if (document.querySelector('.taskList')) {
            document.querySelector('.taskList').innerHTML += html;
        }
    }

    // Add new method to update task list
    updateTaskList(explorer) {


        if (document.querySelector('.taskList')) {
            document.querySelector('.taskList').innerHTML = '';
        }

        const markers = this._dom.get('.mkr');
        markers.forEach(marker => {
            document.body.removeChild(marker);
        });

        const filteredData = this.filterData();

        filteredData.reverse().forEach(task => {
            this.singleTask(task);
            this.createMarker(filteredData.indexOf(task) + 1, task);
        });

        this.attachClickListeners();
    }

    // New method to attach click listeners
    attachClickListeners() {

        console.log("Attaching click listeners..." , this._state.user.role);

        // Remove all existing click listeners first
        const markers = this._dom.get('.mkrClick');
        markers.forEach(marker => {
            const oldClone = marker.cloneNode(true);
            marker.parentNode.replaceChild(oldClone, marker);
        });

        // Add new listeners
        if(this._state.user.role !== 'guest'){
            
        

        const newMarkers = this._dom.get('.mkrClick');
        newMarkers.forEach(marker => {
            marker.addEventListener('click', (e) => {
                this.addClickListener(marker);
            });
        });
    }


        this._state.tasks.forEach(task => {
            const marker = this._dom.getOne(`.mkr[data-mkr-id="${task.id}"]`);

            const {isPermission, isSameUser, role} = this._state.getUserPermissions(task);
            if(marker && isPermission.drag && isSameUser || role === 'admin'){
                const taskDrag = new Dragable({
                    body: `.mkr[data-mkr-id="${task.id}"]`,
                    trigger: `.mkr[data-mkr-id="${task.id}"]`,
                    storageKey: null,
                    type: 'free',
                    initialPosition: {
                        x: task.screeninfo.document.x,
                        y: task.screeninfo.document.y
                    }
                });

                taskDrag.on('dragEnd', async (data) => {
                    console.log('Drag Move', data.position);
                    const payload = {
                        "id": task.id,
                        "x": data.position.x,
                        "y": data.position.y
                    }
                    const res = await this._api.updateTaskPosition(payload);
                    console.log(res);
                });
            }else{
                this._dom.style(marker,{
                    "transform": `translate(${task.screeninfo.document.x}px, ${task.screeninfo.document.y}px)`,
                    "cursor": "not-allowed",
                    "position": "absolute",
                });
            }

        });

        
    }
}