export default class DOM {

    

    Fragment(el) {
        return document.createRange().createContextualFragment(el)
    }

    // create() call that time error. and want to fixed

    create( {
        tag = 'div',
        id = '',
        className = '',
        inner = '',
        isDraggable = false,
        attributes = {}

    }) {
        // if (id === '' && className === '') {
        //     console.error("ID and className cannot be empty");
        // }

        const element = document.createElement(tag);
        if (id) {
            element.id = id;
        }
        if (className) {
            element.className = className;
        }

        if (inner) {
            element.innerHTML = inner;
        }

        if (isDraggable) {
            element.setAttribute('data-no-drag', 'true');
        } 

        // add attributes
        for (const [key, value] of Object.entries(attributes)) {
            element.setAttribute(key, value);
        }

        return element;
    }


    style(element, style) {
        for (const [key, value] of Object.entries(style)) {
            element.style[key] = value;
        }
    }

    // add class
    addClass(element, className , isForce = false) {
        if(!isForce){
            const _className = className.split(' ');
            _className.forEach((el) => {
                element.classList.add(el);
            });
            // element.classList.add(className);
        }else{
            const elements = document.querySelectorAll(element);
            elements.forEach(el => el.classList.add(className));
        }
    }

    // remove class
    removeClass(element, className) {
        element.classList.remove(className);
    }

    // get querySelectorAll
    get(selector) {
        return document.querySelectorAll(selector);
    }

    // get querySelector
    getOne(selector, context = document) {
        if (context) {
            return context.querySelector(selector);
        }else
        {
            return document.querySelector(selector);
        }
        
    }

    // set attribute
    setAttr(element, attribute, value) {
        element.setAttribute(attribute, value);
    }

    // get attribute
    getAttr(element, attribute) {
        return element.getAttribute(attribute);
    }

    /* appendChild */
    append(parent, child) {
        parent.appendChild(child);
    }
    /* removeChild */
    remove(parent, child) {
        parent.removeChild(child);
    }


    /* add event listener */
    on(element, event, callback) {
        element.addEventListener(event, callback);
    }

    /* remove event listener */
    off(element, event, callback) {
        element.removeEventListener(event, callback);
    }
}